const dictionaries: Record<Language, HubDictionary> = { en, es, fr, zh };

export function getHubTranslation(language: Language, key: string): string | undefined {
  if (!(key in en)) return undefined;
  const typedKey = key as HubKey;
  return dictionaries[language][typedKey] ?? en[typedKey];
}
